// index -> strict day json. Regenerated by gen_index.py.
export const DAYS = {
  '-1': dayM1, 0: day0, 1: day1, 2: day2, 3: day3, 4: day4, 5: day5, 6: day6, 7: day7,
  8: day8, 9: day9, 10: day10, 11: day11, 12: day12, 13: day13, 14: day14, 15: day15,
  16: day16, 17: day17, 18: day18, 19: day19, 20: day20, 21: day21, 22: day22, 23: day23,
  24: day24, 25: day25, 26: day26, 27: day27, 28: day28, 29: day29, 30: day30, 31: day31,
  32: day32, 33: day33, 34: day34, 35: day35, 36: day36, 37: day37, 38: day38, 39: day39,
  40: day40, 41: day41, 42: day42, 43: day43, 44: day44, 45: day45, 46: day46, 47: day47,
  48: day48, 49: day49, 50: day50, 51: day51, 52: day52, 53: day53, 54: day54, 55: day55,
  56: day56, 57: day57, 58: day58, 59: day59, 60: day60, 61: day61, 62: day62, 63: day63,
  64: day64,
};

// Calendar anchor: day 0 falls on this local date.
const BASE = new Date(2026, 5, 4); // months are 0-based -> June 4, 2026
const MS_PER_DAY = 86400000;

function atMidnight(d) {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate()).getTime();
}

// Which day index does "today" (the user's local date) correspond to?
export function todayIndex(now = new Date()) {
  return Math.round((atMidnight(now) - atMidnight(BASE)) / MS_PER_DAY);
}

// The calendar Date for a given day index.
export function dateForDay(n) {
  return new Date(atMidnight(BASE) + n * MS_PER_DAY);
}

// Highest day index that actually has data built (the end of the buffer).
export function maxDay() {
  return Math.max(...Object.keys(DAYS).map(Number));
}

const MONTHS = [
  'января', 'февраля', 'марта', 'апреля', 'мая', 'июня',
  'июля', 'августа', 'сентября', 'октября', 'ноября', 'декабря',
];

export function fmtDate(n) {
  const d = dateForDay(n);
  return `${d.getDate()} ${MONTHS[d.getMonth()]} ${d.getFullYear()}`;
}

// Day indexes that actually exist AND whose date has arrived (no spoilers from
// future days), newest first. When `unlocked` (author mode) is true, ALL built
// days are returned — including future ones — so you can play ahead.
export function availableDays(now = new Date(), unlocked = false) {
  const ceil = unlocked ? maxDay() : todayIndex(now);
  return Object.keys(DAYS)
    .map(Number)
    .filter((n) => n <= ceil)
    .sort((a, b) => b - a);
}

// The day to show by default: the latest available one (today, or the most
// recent built day if today's isn't built yet).
export function currentDay(now = new Date()) {
  const avail = availableDays(now);
  return avail.length ? avail[0] : 0;
}

// Resolve a requested ?day=N to a valid, available index (else the current day).
// NOTE: when there is no ?day param, `requested` is null/'' -> must fall back to
// the current day. (Number(null) === 0, so we can't let it reach the parse path,
// or every default visit would land on day 0.)
export function resolveDay(requested, now = new Date(), unlocked = false) {
  if (requested === null || requested === undefined || requested === '') {
    return currentDay(now);
  }
  const n = Number(requested);
  const ceil = unlocked ? maxDay() : todayIndex(now);
  if (Number.isInteger(n) && DAYS[n] && n <= ceil) return n;
  return currentDay(now);
}
